8	-- -------------------------------------------------------------------------------------------------
9	-- Width conversion of an AXI-Stream-like data bus.
10	-- Can handle downsizing (wide to thin) or upsizing (thin to wide).
11	-- The data widths must be a power-of-two multiple of each other. E.g. 10->40 is
12	-- supported while 8->24 is not.
13	--
14	-- There is a generic to enable usage of the ``last`` signal. The ``last`` indicator will be passed
15	-- along with the data from the ``input`` to ``output`` side as-is. Note that enabling the
16	-- ``support_unaligned_packet_length`` generic will enable further processing of ``last``, but in
17	-- barebone configuration the signal is merely passed on.
18	--
19	-- There is a generic to enable strobing of data. The ``strobe`` will be passed on from
20	-- ``input`` to ``output`` side as-is. Note that enabling ``support_unaligned_packet_length``
21	-- generic will enable further processing of ``strobe``, but in barebone configuration the signal
22	-- is merely passed on.
23	-- This means, for example, that there might be output words where all strobe lanes are
24	-- zero when downsizing.
25	--
26	-- There are some limitations, and possible remedies, concerning packet length alignment, depending
27	-- on if we are doing upsizing or downsizing. See below.
28	--
29	--
30	-- Downsizing behavior
31	-- ___________________
32	--
33	-- When doing downsizing, one input beat will result in two or more output beats, depending
34	-- on width configuration. This means that the output packet length is always aligned with the input
35	-- data width. This is not always desirable when working with the ``strobe`` and ``last`` signals.
36	-- Say for example that we are converting a bus from 16 to 8, and ``input_last`` is asserted on a
37	-- beat where the lowest byte is strobed but the highest is not. In this case, we would want
38	-- ``output_last`` to be asserted on the second to last byte, and the last byte (which is strobed
39	-- out) to be removed.
40	-- This is achieved by enabling the ``support_unaligned_packet_length`` generic.
41	-- If the generic is not set, ``output_last`` will be asserted on the very last byte, which will
42	-- be strobed out.
43	--
44	--
45	-- Upsizing behavior
46	-- _________________
47	--
48	-- When upsizing, two or more ``input`` beats result in one ``output`` beat, depending on width
49	-- configuration. This means that the input packet length must be aligned with the output
50	-- data width, so that each packet fills up a whole number of output words.
51	-- If this can not be guaranteed, then the ``support_unaligned_packet_length`` mode can be used.
52	-- When that is enabled, the input stream will be padded upon ``last`` indication so that a whole
53	-- output word is filled.
54	-- Consider the example of converting a bus from 8 to 16, and ``input`` last is asserted on the
55	-- third input beat. If ``support_unaligned_packet_length`` is disabled, there will be one output
56	-- beat sent and half an output beat left in the converter.
57	-- If the mode is enabled however, the input stream will be padded with another byte so that an
58	-- output beat can be sent. The padded parts will have ``strobe`` set to zero.
59	--
60	-- Note that the handling of unaligned packet lengths is highly dependent on the input stream being
61	-- well behaved. Specifically
62	--
63	--   1. There may never be input beats where ``input_strobe`` is all zeros.
64	--   2. For all beats except the one where ``input_last`` is asserted, ``input_strobe`` must be
65	--      asserted on all lanes.
66	--   3. There may never be a ``'1'`` above a ``'0'`` in the ``input_strobe``.
67	--
68	--
69	-- User signalling
70	-- _______________
71	--
72	-- By setting the ``user_width`` generic to a non-zero value, the ``input_user`` port can be used
73	-- to pass auxiliary data along the bus.
74	--
75	-- When downsizing, i.e. when one input beat results in multiple output beats, the
76	-- ``output_user`` port will have the same width as the ``input_user`` port.
77	-- Each output beat will have the same ``user`` value as the input beat that created it.
78	--
79	-- When upsizing, i.e. when multiple input beats result in one output beat, the ``output_user``
80	-- port will have the same width as the ``input_user`` port multiplied by the conversion factor.
81	-- The ``output_user`` port will have the concatenated ``input_user`` values from all the input
82	-- beats that created the output beat.
83	-- -------------------------------------------------------------------------------------------------
84	
85	library ieee;
86	use ieee.std_logic_1164.all;
87	use ieee.numeric_std.all;
88	
89	use work.types_pkg.all;
90	use work.width_conversion_pkg.all;
91	
92	
93	entity width_conversion is
94	  generic (
95	    input_width : positive;
96	    output_width : positive;
97	    -- Enable usage of the 'input_last' and 'output_last' ports.
98	    -- Will increase the logic footprint.
99	    enable_last : boolean := false;
100	    -- Enable usage of the 'input_strobe' and 'output_strobe' ports.
101	    -- Will increase the logic footprint.
102	    enable_strobe : boolean := false;
103	    -- In the typical use case where we want a "byte strobe", this would be eight.
104	    -- In other cases, for example when the data is packed, we might use a higher value.
105	    -- Must assign a valid value if 'enable_strobe' is true.
106	    strobe_unit_width : positive := 8;
107	    -- Width of the 'input_user' port.
108	    user_width : natural := 0;
109	    -- Enable if 'input' packet lengths are not a multiple of the 'output' width.
110	    -- Must set 'enable_strobe' and 'enable_last' as well to use this.
111	    -- See header for details about how this works.
112	    -- Will increase the logic footprint.
113	    support_unaligned_packet_length : boolean := false
114	  );
115	  port (
116	    clk : in std_ulogic;
117	    --# {{}}
118	    input_ready : out std_ulogic := '0';
119	    input_valid : in std_ulogic;
120	    -- Optional packet 'last' signalling. Must set 'enable_last' generic in order to use this.
121	    input_last : in std_ulogic := '0';
122	    input_data : in std_ulogic_vector(input_width - 1 downto 0);
123	    -- Optional word strobe. Must set 'enable_strobe' generic in order to use this.
124	    input_strobe : in std_ulogic_vector(input_width / strobe_unit_width - 1 downto 0) := (
125	      others => '1'
126	    );
127	    -- Optional auxiliary user data. Must set 'user_width' generic in order to use this.
128	    input_user : in std_ulogic_vector(user_width - 1 downto 0) := (others => '-');
129	    --# {{}}
130	    output_ready : in std_ulogic;
131	    output_valid : out std_ulogic := '0';
132	    -- Optional packet 'last' signalling. Must set 'enable_last' generic in order to use this.
133	    output_last : out std_ulogic := '0';
134	    output_data : out std_ulogic_vector(output_width - 1 downto 0) := (others => '0');
135	    -- Optional word strobe. Must set 'enable_strobe' generic in order to use this.
136	    output_strobe : out std_ulogic_vector(output_width / strobe_unit_width - 1 downto 0) := (
137	      others => '1'
138	    );
139	    -- Optional auxiliary user data. Must set 'user_width' generic in order to use this.
140	    output_user : out std_ulogic_vector(
141	      width_conversion_output_user_width(
142	        input_user_width=>user_width, input_data_width=>input_width, output_data_width=>output_width
143	      ) - 1
144	      downto 0
145	    ) := (others => '0')
146	  );
147	end entity;
148	
149	architecture a of width_conversion is
150	
151	  constant is_upsizing : boolean := input_width < output_width;
152	  constant is_downsizing : boolean := input_width > output_width;
153	
154	  constant enable_user : boolean := user_width > 0;
155	
156	  -- When converting e.g. 16->32 the data atom that is handled internally will be of width 16.
157	  -- This gives lower resource utilization than if it was e.g. always 8.
158	  constant atom_data_width : positive := minimum(input_width, output_width);
159	  constant atom_strobe_width : positive := atom_data_width / strobe_unit_width;
160	  constant atom_user_width : natural := user_width;
161	
162	  subtype atom_data_t is std_ulogic_vector(atom_data_width - 1 downto 0);
163	  subtype atom_strobe_t is std_ulogic_vector(atom_strobe_width - 1 downto 0);
164	  subtype atom_user_t is std_ulogic_vector(user_width - 1 downto 0);
165	
166	  constant input_width_atoms : positive := input_width / atom_data_width;
167	  constant output_width_atoms : positive := output_width / atom_data_width;
168	
169	  type atom_t is record
170	    last : std_ulogic;
171	    data : atom_data_t;
172	    strobe : atom_strobe_t;
173	    user : atom_user_t;
174	  end record;
175	  constant atom_init : atom_t := (
176	    last => '0',
177	    data => (others => '0'),
178	    strobe => (others => '0'),
179	    user => (others => '0')
180	  );
181	  type atom_vec_t is array (integer range <>) of atom_t;
182	
183	  constant packed_atom_width : positive := (
184	    atom_data_width + to_int(enable_last) + to_int(enable_strobe) * atom_strobe_width + user_width
185	  );
186	  subtype packed_atom_t is std_ulogic_vector(packed_atom_width - 1 downto 0);
187	
188	  constant packed_input_width : positive := input_width_atoms * packed_atom_width;
189	  signal input_packed : std_ulogic_vector(packed_input_width - 1 downto 0) := (others => '0');
190	
191	  constant stored_atom_count_max : positive := input_width_atoms + output_width_atoms;
192	  constant shift_reg_length : positive := stored_atom_count_max * packed_atom_width;
193	  signal shift_reg : std_ulogic_vector(shift_reg_length - 1 downto 0) := (others => '0');
194	
195	  signal num_atoms_stored : natural range 0 to stored_atom_count_max := 0;
196	
197	  signal padded_input_ready, padded_input_valid, padded_input_last : std_ulogic := '0';
198	  signal padded_input_data : std_ulogic_vector(input_data'range) := (others => '0');
199	  signal padded_input_strobe : std_ulogic_vector(input_strobe'range) := (others => '0');
200	  signal padded_input_user : std_ulogic_vector(input_user'range) := (others => '0');
201	
202	  signal output_ready_int, output_valid_int, output_last_int : std_ulogic := '0';
203	  signal output_strobe_int : std_ulogic_vector(output_strobe'range) := (others => '0');
204	
205	begin
206	
207	  ------------------------------------------------------------------------------
208	  assert input_width /= output_width
209	    report "Do not use this module with equal widths"
210	    severity failure;
211	
212	  assert input_width mod output_width = 0 or output_width mod input_width = 0
213	    report "Larger width has to be multiple of smaller."
214	    severity failure;
215	
216	  assert (output_width / input_width) mod 2 = 0 and (input_width / output_width) mod 2 = 0
217	    report "Larger width has to be power-of-two multiple of smaller."
218	    severity failure;
219	
220	  assert (
221	      (not enable_strobe)
222	      or (input_width mod strobe_unit_width = 0 and output_width mod strobe_unit_width = 0)
223	    )
224	    report "Data width must be a multiple of strobe unit width."
225	    severity failure;
226	
227	  assert enable_strobe or not support_unaligned_packet_length
228	    report "Must enable strobing when doing unaligned packets."
229	    severity failure;
230	
231	  assert enable_last or not support_unaligned_packet_length
232	    report "Must enable 'last' when doing unaligned packets."
233	    severity failure;
234	
235	
236	  ------------------------------------------------------------------------------
237	  assertions : process
238	    constant strobe_init : std_ulogic_vector(input_strobe'range) := (others => '1');
239	  begin
240	    wait until rising_edge(clk);
241	
242	    if input_valid then
243	      assert enable_last or input_last = '0'
244	        report "Must enable 'last' using generic";
245	
246	      assert enable_strobe or input_strobe = strobe_init
247	        report "Must enable 'strobe' using generic";
248	    end if;
249	  end process;
250	
251	
252	  ------------------------------------------------------------------------------
253	  pad_input_data_generate : if is_upsizing and support_unaligned_packet_length generate
254	    type state_t is (let_data_pass, send_padding);
255	    signal state : state_t := let_data_pass;
256	
257	    constant width_ratio : positive := output_width / input_width;
258	    signal beats_filled : natural range 0 to width_ratio - 1 := 0;
259	  begin
260	
261	    ------------------------------------------------------------------------------
262	    assign : process(all)
263	    begin
264	      padded_input_data <= input_data;
265	
266	      -- 'last' when in padding state does not matter.
267	      -- When in this unaligned mode, 'output_last' is set by OR'ing  the 'last' for each atom.
268	      padded_input_last <= input_last;
269	
270	      padded_input_user <= input_user;
271	
272	      if state = let_data_pass then
273	        -- Passthrough.
274	        input_ready <= padded_input_ready;
275	        padded_input_valid <= input_valid;
276	        padded_input_strobe <= input_strobe;
277	
278	      else
279	        -- send_padding
280	        input_ready <= '0';
281	        padded_input_valid <= '1';
282	        padded_input_strobe <= (others => '0');
283	
284	      end if;
285	    end process;
286	
287	
288	    ------------------------------------------------------------------------------
289	    pad_input_data : process
290	    begin
291	      wait until rising_edge(clk) and support_unaligned_packet_length;
292	
293	      if padded_input_ready and padded_input_valid then
294	        beats_filled <= (beats_filled + 1) mod width_ratio;
295	      end if;
296	
297	      case state is
298	        when let_data_pass =>
299	          if (
300	            padded_input_ready = '1'
301	            and padded_input_valid = '1'
302	            and padded_input_last = '1'
303	            and beats_filled /= width_ratio - 1
304	          ) then
305	            state <= send_padding;
306	          end if;
307	
308	        when send_padding =>
309	          if padded_input_ready and padded_input_valid then
310	            if beats_filled = width_ratio - 1 then
311	              -- This transaction fills the last atom(s) needed for a whole output beat
312	              state <= let_data_pass;
313	            end if;
314	          end if;
315	
316	      end case;
317	    end process;
318	
319	  else generate
320	
321	    -- Passthrough.
322	    input_ready <= padded_input_ready;
323	    padded_input_valid <= input_valid;
324	    padded_input_last <= input_last;
325	    padded_input_data <= input_data;
326	    padded_input_strobe <= input_strobe;
327	    padded_input_user <= input_user;
328	
329	  end generate;
330	
331	
332	  ------------------------------------------------------------------------------
333	  pack_input_block : block
334	    signal input_atoms : atom_vec_t(0 to input_width_atoms - 1) := (others => atom_init);
335	  begin
336	
337	    ------------------------------------------------------------------------------
338	    split_input_to_atoms : process(all)
339	      variable is_last_atom : std_ulogic := '0';
340	    begin
341	      for atom_idx in input_atoms'range loop
342	        input_atoms(atom_idx).data <= padded_input_data(
343	          (atom_idx + 1) * atom_data_width - 1 downto atom_idx * atom_data_width
344	        );
345	        input_atoms(atom_idx).strobe <= padded_input_strobe(
346	          (atom_idx + 1) * atom_strobe_width - 1 downto atom_idx * atom_strobe_width
347	        );
348	        input_atoms(atom_idx).user <= padded_input_user;
349	      end loop;
350	
351	      for atom_idx in input_atoms'range loop
352	        if is_downsizing and support_unaligned_packet_length then
353	          -- Set 'last' only on the last strobed atom of the input word.
354	          if atom_idx = input_atoms'high then
355	            is_last_atom := input_atoms(atom_idx).strobe(0);
356	          else
357	            is_last_atom := (
358	              input_atoms(atom_idx).strobe(0) and (not input_atoms(atom_idx + 1).strobe(0))
359	            );
360	          end if;
361	        else
362	          -- In regular mode, this last atom is simple the top one.
363	          is_last_atom := to_sl(atom_idx = input_atoms'high);
364	        end if;
365	
366	        input_atoms(atom_idx).last <= padded_input_last and is_last_atom;
367	      end loop;
368	    end process;
369	
370	
371	    ------------------------------------------------------------------------------
372	    pack_input : process(all)
373	      variable packed_atom : packed_atom_t := (others => '0');
374	      variable hi, lo : natural range packed_atom'range := 0;
375	    begin
376	      for input_atom_idx in input_atoms'range loop
377	        lo := 0;
378	        hi := input_atoms(0).data'length - 1;
379	        packed_atom(hi downto lo) := input_atoms(input_atom_idx).data;
380	
381	        if enable_strobe then
382	          -- Could be more than one bit
383	          lo := hi + 1;
384	          hi := lo + input_atoms(0).strobe'length - 1;
385	          packed_atom(hi downto lo) := input_atoms(input_atom_idx).strobe;
386	        end if;
387	
388	        if enable_user then
389	          -- Could be more than one bit
390	          lo := hi + 1;
391	          hi := lo + input_atoms(0).user'length - 1;
392	          packed_atom(hi downto lo) := input_atoms(input_atom_idx).user;
393	        end if;
394	
395	        if enable_last then
396	          -- Only one bit
397	          hi := hi + 1;
398	          packed_atom(hi) := input_atoms(input_atom_idx).last;
399	        end if;
400	
401	        assert hi = packed_atom'high;
402	
403	        input_packed(
404	          (input_atom_idx + 1) * packed_atom'length - 1 downto input_atom_idx * packed_atom'length
405	        ) <= packed_atom;
406	      end loop;
407	    end process;
408	
409	  end block;
410	
411	
412	  ------------------------------------------------------------------------------
413	  main : process
414	    variable num_atoms_next : natural range 0 to stored_atom_count_max := 0;
415	  begin
416	    wait until rising_edge(clk);
417	
418	    if padded_input_ready and padded_input_valid then
419	      shift_reg <= (
420	        input_packed
421	        & shift_reg(shift_reg'left downto input_packed'length)
422	      );
423	    end if;
424	
425	    num_atoms_next := (
426	      num_atoms_stored
427	      + to_int(padded_input_ready and padded_input_valid) * input_width_atoms
428	      - to_int(output_ready_int and output_valid_int) * output_width_atoms
429	    );
430	
431	    num_atoms_stored <= num_atoms_next;
432	
433	    output_valid_int <= to_sl(num_atoms_next >= output_width_atoms);
434	  end process;
435	
436	  padded_input_ready <= to_sl(num_atoms_stored <= stored_atom_count_max - input_width_atoms);
437	
438	
439	  ------------------------------------------------------------------------------
440	  unpack_output_block : block
441	    signal output_atoms : atom_vec_t(0 to output_width_atoms - 1) := (others => atom_init);
442	  begin
443	
444	    ------------------------------------------------------------------------------
445	    slice_output : process(all)
446	      variable output_atoms_base : natural range 0 to stored_atom_count_max := 0;
447	
448	      variable packed_atom : packed_atom_t := (others => '0');
449	      variable hi, lo : natural range packed_atom'range := 0;
450	    begin
451	      output_atoms_base := stored_atom_count_max - num_atoms_stored;
452	
453	      for output_atom_idx in 0 to output_width_atoms - 1 loop
454	        if output_atom_idx < num_atoms_stored then
455	          packed_atom := shift_reg(
456	            (output_atoms_base + output_atom_idx + 1) * packed_atom_width - 1
457	            downto (output_atoms_base + output_atom_idx) * packed_atom_width
458	          );
459	        else
460	          -- This is just so that the indexing does not go out of range.
461	          -- When the condition for output_valid is met, we will not end up here for any atom.
462	          -- Typically we would assign '-' here, to instruct Vivado that the 'if' logic can be
463	          -- be stripped.
464	          -- However, in this case that showed to increase the logic footprint quite considerably.
465	          -- At this point it is unclear why, but it is a clear difference in the netlist builds.
466	          -- Note that we have tried re-formulating this part of the code in A LOT of
467	          -- different ways.
468	          -- We have not found any way that is more efficient than this.
469	          packed_atom := (others => '0');
470	        end if;
471	
472	        lo := 0;
473	        hi := output_atoms(0).data'length - 1;
474	        output_atoms(output_atom_idx).data <= packed_atom(hi downto lo);
475	
476	        if enable_strobe then
477	          -- Could be more than one bit
478	          lo := hi + 1;
479	          hi := lo + output_atoms(0).strobe'length - 1;
480	          output_atoms(output_atom_idx).strobe <= packed_atom(hi downto lo);
481	        end if;
482	
483	        if enable_user then
484	          -- Could be more than one bit
485	          lo := hi + 1;
486	          hi := lo + output_atoms(0).user'length - 1;
487	          output_atoms(output_atom_idx).user <= packed_atom(hi downto lo);
488	        end if;
489	
490	        if enable_last then
491	          -- Only one bit
492	          hi := hi + 1;
493	          output_atoms(output_atom_idx).last <= packed_atom(hi);
494	        end if;
495	
496	        assert hi = packed_atom'high;
497	      end loop;
498	    end process;
499	
500	
501	    ------------------------------------------------------------------------------
502	    assign_output : process(all)
503	      variable output_last_or : std_ulogic := '0';
504	    begin
505	      output_last_or := '0';
506	
507	      for output_atom_idx in 0 to output_width_atoms - 1 loop
508	        output_data(
509	          (output_atom_idx + 1) * atom_data_width - 1 downto output_atom_idx * atom_data_width
510	        ) <= output_atoms(output_atom_idx).data;
511	
512	        output_strobe_int(
513	          (output_atom_idx + 1) * atom_strobe_width - 1 downto output_atom_idx * atom_strobe_width
514	        ) <= output_atoms(output_atom_idx).strobe;
515	
516	        output_user(
517	          (output_atom_idx + 1) * atom_user_width - 1 downto output_atom_idx * atom_user_width
518	        ) <= output_atoms(output_atom_idx).user;
519	
520	        output_last_or := output_last_or or output_atoms(output_atom_idx).last;
521	      end loop;
522	
523	      if is_upsizing and support_unaligned_packet_length then
524	        -- The top atom might be strobed out and not have 'last' set.
525	        -- Instead it is found in one of the lower atoms.
526	        output_last_int <= output_last_or;
527	
528	      else
529	        -- In the regular case though, the top atom is the one that has 'last' set.
530	        output_last_int <= output_atoms(output_atoms'high).last;
531	      end if;
532	    end process;
533	
534	  end block;
535	
536	
537	  ------------------------------------------------------------------------------
538	  strip_output_data_generate : if is_downsizing and support_unaligned_packet_length generate
539	    signal strobe_all_zero : std_ulogic_vector(output_strobe'range) := (others => '0');
540	  begin
541	
542	    -- The write processing will place 'last' indicator on the last atom that is strobed.
543	    -- There might come atoms after that, since this is downsizing.
544	    -- If those atoms add up to an output beat, that is removed here.
545	    -- This is highly dependent on the input stream being well-behaved.
546	
547	    ------------------------------------------------------------------------------
548	    set_output : process(all)
549	    begin
550	      -- Pop strobed out words
551	      output_ready_int <= (
552	        output_ready or (output_valid_int and to_sl(output_strobe_int = strobe_all_zero))
553	      );
554	
555	      -- Do not pass on strobed out words
556	      output_valid <= output_valid_int and to_sl(output_strobe_int /= strobe_all_zero);
557	
558	      output_last <= output_last_int;
559	      output_strobe <= output_strobe_int;
560	    end process;
561	
562	
563	  ------------------------------------------------------------------------------
564	  else generate
565	
566	    -- Passthrough
567	
568	    ------------------------------------------------------------------------------
569	    set_output : process(all)
570	    begin
571	      output_ready_int <= output_ready;
572	      output_valid <= output_valid_int;
573	
574	      if enable_last then
575	        output_last <= output_last_int;
576	      end if;
577	
578	      if enable_strobe then
579	        output_strobe <= output_strobe_int;
580	      end if;
581	    end process;
582	
583	  end generate;
584	
585	end architecture;
586

