33	  signal count_enable : std_ulogic := '1';
34	  signal pulse : std_ulogic := '0';
35	
36	  signal start_test, test_done : boolean := false;
37	
38	begin
39	
40	  clk <= not clk after 5 ns;
41	
42	  test_runner_watchdog(runner, 1 ms);
43	
