45	  ------------------------------------------------------------------------------
46	  main : process
47	  begin
48	    test_runner_setup(runner, runner_cfg);
49	
50	    wait until rising_edge(clk);
51	    start_test <= true;
52	
53	    wait until rising_edge(clk) and test_done;
54	
55	    test_runner_cleanup(runner);
56	  end process;
57	
