60	  stimuli : process
61	    variable rnd : RandomPType;
62	  begin
63	    wait until rising_edge(clk) and start_test;
64	    loop
65	      wait until rising_edge(clk);
66	      count_enable <= rnd.RandSlv(1)(1);
67	    end loop;
68	  end process;
