73	    constant num_pulses_to_check : integer := 3;
74	    variable tick_count : integer range 0 to period - 1;
75	    variable num_pulses : integer range 0 to num_pulses_to_check := 0;
76	    variable expected_pulse : std_ulogic := '0';
77	  begin
78	    wait until rising_edge(clk);
79	    expected_pulse := '0';
80	    if count_enable then
81	      if tick_count = period - 1 then
82	        tick_count := 0;
83	        expected_pulse := '1';
84	      else
85	        tick_count := tick_count + 1;
86	      end if;
87	    end if;
88	
89	    check_equal(pulse, expected_pulse, "Pulse seen at unexpected time");
90	    if expected_pulse then
91	      num_pulses := num_pulses + 1;
92	      if num_pulses = num_pulses_to_check then
93	        test_done <= true;
94	      end if;
95	    end if;
96	  end process;
97	
98	
99	  ------------------------------------------------------------------------------
100	  dut : entity work.periodic_pulser
101	    generic map (
102	      period => period,
103	      shift_register_length => shift_register_length
104	    )
105	    port map (
106	      clk => clk,
107	      count_enable => count_enable,
108	      pulse => pulse
109	    );
